2	 * Drives the live backend connection during onboarding: fetches the initial
3	 * personalization snapshot via REST, opens a WebSocket for stage events, and
4	 * falls back to REST polling if the socket goes silent.
5	 */
6	
7	"use client";
8	
9	import { type Dispatch, useEffect, useRef } from "react";
10	
11	import { getPersonalization } from "../api/onboardingApi";
12	import type { Action, OnboardingState, Stage } from "../state/types";
13	import type {
14	  OnboardingStage,
15	  PersonalizationData,
