2	 * Full-screen layout wrapper for the onboarding page. Three regions: top
3	 * progress bar, scrollable content (caller-supplied children), and an
4	 * optional pinned composer at the bottom. Auto-scrolls the content region
5	 * to bottom whenever stage- or content-bearing state changes.
6	 */
7	
8	"use client";
9	
10	import type { ReactNode } from "react";
