  +        if (response?.success && response.user) {
  +          onSuccess?.(response.user);
  +        }
  +      })
  +      .catch((error: unknown) => {
  +        const err = error as { response?: { status?: number } };
  +        if (err?.response?.status === 409) {
  +          return;
  +        }
  +        dispatch({ type: "submitError" });
  +      })
  +      .finally(() => {
  +        inFlightRef.current = false;
  +      });
  +  }, [state, dispatch, onSuccess]);
  +}
