() => {
  const userId = (() => {
    try {
      const raw = localStorage.getItem("userStore");
      if (!raw) return null;
      return JSON.parse(raw)?.state?.userId ?? null;
    } catch { return null; }
  })();
  const onboarding = (() => {
    try {
      const raw = localStorage.getItem("userStore");
      if (!raw) return null;
      return JSON.parse(raw)?.state?.onboarding ?? null;
    } catch { return null; }
  })();
  const obState = (() => {
    try {
      return JSON.parse(localStorage.getItem("gaia-onboarding-state-v2") ?? "null");
    } catch { return null; }
  })();
  return {
    pathname: location.pathname,
    userId,
    onboarding_user_store: onboarding,
    persisted_onboarding_state: obState,
  };
}

