215	            );
216	          })}
217	        </Tabs>
218	        <span className="text-xs text-zinc-500">
219	          {answeredCount} / {questions.length}
220	        </span>
221	      </div>
222	
223	      <AnimatePresence mode="wait" initial={false}>
224	        <m.div
225	          key={activeQuestion.id}
226	          initial={{ opacity: 0, y: 8 }}
227	          animate={{ opacity: 1, y: 0 }}
228	          exit={{ opacity: 0, y: -8 }}
229	          transition={{ duration: 0.25, ease: EASE_OUT_QUART }}
230	          className="rounded-2xl bg-zinc-900 p-3"
231	        >
232	          <p className="mb-3 text-sm text-zinc-100">
233	            {activeQuestion.question}
234	          </p>
235	
236	          <RadioGroup
237	            value={selectedValue ?? ""}
238	            onValueChange={handleRadioChange}
239	            classNames={{ wrapper: "gap-1.5" }}
240	          >
241	            {activeQuestion.options.map((option, idx) => (
242	              <Radio
243	                key={option}
244	                value={`${OPTION_VALUE_PREFIX}${idx}`}
245	                classNames={{
246	                  base: CLARIFY_RADIO_BASE_CLASS,
247	                  label: CLARIFY_RADIO_LABEL_CLASS,
248	                }}
249	              >
250	                {option}
251	              </Radio>
252	            ))}
253	            <Radio
254	              value={OTHER_VALUE}
255	              classNames={{
256	                base: CLARIFY_RADIO_BASE_CLASS,
257	                label: CLARIFY_RADIO_LABEL_CLASS,
258	              }}
259	            >
260	              {CLARIFY_OTHER_LABEL}
261	            </Radio>
262	            <AnimatePresence initial={false}>
263	              {isOtherSelected && (
264	                <m.div
265	                  initial={{ opacity: 0, height: 0 }}
266	                  animate={{ opacity: 1, height: "auto" }}
267	                  exit={{ opacity: 0, height: 0 }}
268	                  transition={{ duration: 0.25, ease: EASE_OUT_QUART }}
269	                  className="overflow-hidden"
270	                >
271	                  <Input
272	                    autoFocus
273	                    size="sm"
274	                    value={activeDraft}
275	                    onValueChange={handleCustomChange}
276	                    onBlur={handleCustomCommit}
277	                    placeholder="Type your answer..."
278	                    classNames={{
279	                      inputWrapper:
280	                        "bg-zinc-800 shadow-none data-[hover=true]:bg-zinc-800 group-data-[focus=true]:bg-zinc-800",
281	                    }}
282	                  />
283	                </m.div>
284	              )}
285	            </AnimatePresence>
286	            <Radio
287	              value={SKIP_VALUE}
288	              classNames={{
289	                base: CLARIFY_RADIO_BASE_CLASS,
290	                label: CLARIFY_RADIO_LABEL_MUTED_CLASS,
291	              }}
292	            >
293	              {CLARIFY_SKIP_LABEL}
294	            </Radio>
295	          </RadioGroup>
296	        </m.div>
297	      </AnimatePresence>
298	
299	      <div className="mt-3 flex justify-end">
300	        <Button
301	          color="primary"
302	          radius="full"
303	          size="sm"
304	          isDisabled={!allAnswered}
305	          onPress={handleSubmit}
306	          endContent={<CircleArrowRight02Icon className="size-4" />}
307	        >
308	          Submit & continue
309	        </Button>
310	      </div>
311	    </m.div>
312	  );
313	}
